class SoapActionRouterMiddleware:
    """
    Ensures operation routing via SOAPAction by rewriting PATH_INFO to include the
    operation name, so Spyne's WsgiApplication can dispatch appropriately.
    """
    def __init__(self, spyne_wsgi_app, service_path="/soap"):
        self.app = spyne_wsgi_app
        self.service_path = service_path.rstrip("/") or "/soap"

    @staticmethod
    def _parse_soapaction(environ):
        sa = environ.get("HTTP_SOAPACTION")
        if not sa:
            return None
        sa = sa.strip()
        if len(sa) >= 2 and sa[0] == '"' and sa[-1] == '"':
            sa = sa[1:-1]
        sa = sa.strip()
        if not sa:
            return None
        if "#" in sa:
            return sa.rsplit("#", 1)[-1].strip()
        if "/" in sa:
            return sa.rsplit("/", 1)[-1].strip()
        return sa

    def __call__(self, environ, start_response):
        path = environ.get("PATH_INFO", "")
        if path.rstrip("/") == self.service_path:
            op = self._parse_soapaction(environ)
            if op:
                environ["PATH_INFO"] = f"{self.service_path}/{op}"
        return self.app(environ, start_response)


